var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"시공간 수정의 후유증은 꽤나 다양해, 친구.","JPN":"時空間修正の後遺症は、かなり様々だ。","ENG":"Side effects of spacetime recalibration are quite diverse, my friend.","TWN":"修正時空會引起多種後遺症，朋友。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"특히나 자네처럼 많이 겪은 경우에는...... 무슨 일이 일어날지 장담할 수 없어.","JPN":"特に君のように、色んなことがあった場合……何が起きるかわからない。","ENG":"And for someone who has done it multiple times like yourself, there's no telling what might happen.","TWN":"特別是像你這種經歷了很多次的情況……我無法保證會發生什麼。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"하지만 자네의 길잡이로서, 이것 하나는 얘기해 줄 수 있겠군.","JPN":"だが、君のガイドとして、これだけは言える。","ENG":"But as your guide, I can tell you this.","TWN":"但作為你的領路人，我可以告訴你一點。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"꿈에서 다른 사람과 눈을 마주치게 되더라도 너무 놀라진 마. 그건 실제가 아니고, 그들의 추억을 잠시 관측하는 것 뿐이니까.","JPN":"夢の中で他の人と目が合っても、あまり驚くな。それは現実ではなく、彼らの思い出を少し観察するにすぎない。","ENG":"Don't be too surprised if you get to make eye contact with someone else. It's not real. You're observing their memories for a short period of time.","TWN":"在夢裡，即使與他人對上視線也不要太驚訝。因為那並不是現實，你只是在暫時觀看他們的回憶而已。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"하지만 사람들의 행복했던 시절을 함께 돌아보는 것도...... 자네가 앞으로 걸을 길에 작은 위안 정도는 되겠지.","JPN":"だが、誰かの幸せだった時期を一緒に振り返るのも……これから君が歩むべき道の、小さな癒しにはなるだろう。","ENG":"But looking back at people's memories of their happy past could provide some comfort for your mind while walking the path you're on.","TWN":"不過，與他人一同觀看幸福的回憶……或許能成為你前進的道路上的小小慰藉。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"와, 날씨가 엄청 좋네. 오늘 소풍 나오길 잘했다. 그치?","JPN":"わあ、今日はすごく天気がいいね。ピクニックに来てよかった。ね？","ENG":"Wow, what a lovely day! Picnic was a good idea, don't you think?","TWN":"哇，天氣真好啊。還好今天出來散步了。對吧？"},"stage":{"bg":"PARK","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"YUMI_POLICE_NULL_CHILD","text":{"KOREA":"응! 빵도 맛있는 것들로 잔뜩 담아왔어.","JPN":"うん！　おいしいパンもいっぱい持ってきたよ。","ENG":"Yeah! And I've packed all kinds of bread in the basket.","TWN":"嗯！我帶來了很多好吃的麵包喲。"},"stage":{"bg":"PARK","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"앗, 너무 많이 먹으면 안돼. 이따가 엄마가 챙겨준 도시락도 먹어야 하니까.","JPN":"あっ、食べ過ぎちゃだめ。お母さんが作ってくれたお弁当もあるから。","ENG":"Ah, but you'll need to save room for the lunch Mom made us.","TWN":"啊，不要吃太多。待會兒還要吃媽媽做的便當呢。"},"stage":{"bg":"PARK","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"YUMI_POLICE_NULL_CHILD","text":{"KOREA":"걱정 마. 다 먹을 수 있거든.","JPN":"大丈夫。全部食べられるもん。","ENG":"Don't worry. I can handle that much.","TWN":"別擔心。我都能吃完的。"},"stage":{"bg":"PARK","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_CHILD","face":"UNIT_TOUCH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":null,"text":{"KOREA":"하하......","JPN":"はは……","ENG":"Hah hah...","TWN":"哈哈……"},"stage":{"bg":"PARK","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"PARK","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"있지. 유미는 커서 어른이 되면, 뭘 하고 있을 거 같아?","JPN":"ねえ、ユミは大人になったらどんな仕事をしてるかな？","ENG":"Hey, Yumi. What do you think you want to do when you grow up?","TWN":"那個。悠美長大後，想做什麼呢？"},"stage":{"bg":"PARK","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YUMI_POLICE_NULL_CHILD","text":{"KOREA":"음......","JPN":"うーん……","ENG":"Umm...","TWN":"嗯……"},"stage":{"bg":"PARK","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YUMI_POLICE_NULL_CHILD","text":{"KOREA":"......빵?","JPN":"……パン？","ENG":"Bake bread?","TWN":"……麵包？"},"stage":{"bg":"PARK","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":null,"text":{"KOREA":"아하, 제빵사가 되고 싶다는 거지?","JPN":"あ、パン屋さんになりたいの？","ENG":"Ah, you want to be a baker?","TWN":"啊哈，是想當麵包師傅嗎？"},"stage":{"bg":"PARK","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"YUMI_POLICE_NULL_CHILD","text":{"KOREA":"과자 만드는 것도 좋아. 언니가 과자 좋아하고, 나도 좋아하니까.","JPN":"お菓子を作るのも好き。お姉ちゃんがお菓子好きだし、私も好きだから。","ENG":"I want to bake cookies as well. You like cookies, and I like cookies.","TWN":"做餅乾也不錯。因為姐姐喜歡吃，所以我也喜歡吃。"},"stage":{"bg":"PARK","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_CHILD","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":null,"text":{"KOREA":"응. 그거 좋겠다.","JPN":"うん、それいいね。","ENG":"Yes, that sounds wonderful.","TWN":"嗯。不錯不錯。"},"stage":{"bg":"PARK","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"YUMI_POLICE_NULL_CHILD","text":{"KOREA":"......언니는 크면 뭐가 하고 싶은데?","JPN":"……お姉ちゃんは？","ENG":"What do you want to do when you grow up?","TWN":"……姐姐長大後想當什麼呀？"},"stage":{"bg":"PARK","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":null,"text":{"KOREA":"음, 글쎄......","JPN":"うーん、どうだろう……","ENG":"Um, I don't know.","TWN":"嗯，我想想……"},"stage":{"bg":"PARK","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_CHILD","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};